CREATE TABLE Employee (
    EmpID  INT PRIMARY KEY,
    Name   VARCHAR(50) NOT NULL,
    Dept   VARCHAR(20),
    Salary DECIMAL(10,2) CHECK (Salary > 0),
    DeptID INT REFERENCES Department(DeptID)
);

ALTER TABLE Employee ADD Email VARCHAR(60);
DROP TABLE Employee;

