WHERE Dept = 'CSE';

DELETE FROM Employee WHERE Salary < 50000;

CREATE VIEW HighEarners AS
SELECT Name, Dept, Salary
FROM   Employee
WHERE  Salary > 70000;

-- Use it like a normal table:
SELECT * FROM HighEarners;

